#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 1e5+5;
int n,m,a[N],Mx[N],Mn[N],tmp[N],dp[N],c[N],Ans;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
bool cmp1(int x,int y){return Mx[x]<Mx[y];}
bool cmp2(int x,int y){return a[x]<a[y];}
void upd(int x,int k){while(x<N)c[x]=max(c[x],k),x+=x&-x;return;}
int ask(int x){int sum=0;while(x)sum=max(sum,c[x]),x-=x&-x;return sum;}
void clr(int x){while(x<N)c[x]=0,x+=x&-x;return;}
void CDQsolve(int l,int r){
    if(l==r){dp[l]=max(dp[l],1);return;}
    int mid=(l+r)>>1;CDQsolve(l,mid);
    for(int i=l;i<=r;i++)tmp[i]=i;
    sort(tmp+l,tmp+mid+1,cmp1);
    sort(tmp+mid+1,tmp+r+1,cmp2);
    for(int i=l,j=mid+1;j<=r;j++){
        while(i<=mid&&Mx[tmp[i]]<=a[tmp[j]])
            upd(a[tmp[i]],dp[tmp[i]]),++i;
        dp[tmp[j]]=max(dp[tmp[j]],ask(Mn[tmp[j]])+1);
    }
    for(int i=l;i<=mid;i++)clr(a[i]);
    CDQsolve(mid+1,r);return;
}
int main(){
    n=read(),m=read();
    for(int i=1;i<=n;i++)
        a[i]=read(),Mx[i]=a[i],Mn[i]=a[i];
    for(int i=1;i<=m;i++){
        int x=read(),y=read();
        Mx[x]=max(Mx[x],y),Mn[x]=min(Mn[x],y);
    }CDQsolve(1,n),Ans=0;
    for(int i=1;i<=n;i++)Ans=max(Ans,dp[i]);
    cout<<Ans<<"\n";
    return 0;
}
